+    function applyShellState(shell) {
+      const balance = shell.dataset.balance || "balanced";
+      const rail = shell.dataset.rail || "expanded";
+
+      for (const button of shell.querySelectorAll("[data-shell-balance]")) {
+        button.setAttribute("aria-pressed", String(button.dataset.shellBalance === balance));
+      }
+
+      for (const button of shell.querySelectorAll("[data-shell-rail]")) {
+        button.dataset.rail = rail;
+        if (button.dataset.shellTarget === "support") {
+          button.textContent = rail === "collapsed" ? "Show Notes" : "Collapse Notes";
+        } else {
+          button.textContent = rail === "collapsed" ? "Show Rail" : "Collapse Rail";
+        }
+      }
+    }
+
+    function initShellControls() {
+      for (const shell of document.querySelectorAll("[data-shell]")) {
+        applyShellState(shell);
+      }
+
+      document.addEventListener("click", (event) => {
+        const balanceButton = event.target.closest("[data-shell-balance]");
+        if (balanceButton) {
+          const shell = document.querySelector(`[data-shell="${balanceButton.dataset.shellTarget}"]`);
+          if (!shell) {
+            return;
+          }
+          shell.dataset.balance = balanceButton.dataset.shellBalance;
+          applyShellState(shell);
+          return;
+        }
+
+        const railButton = event.target.closest("[data-shell-rail]");
+        if (railButton) {
+          const shell = document.querySelector(`[data-shell="${railButton.dataset.shellTarget}"]`);
+          if (!shell) {
+            return;
+          }
+          shell.dataset.rail = shell.dataset.rail === "collapsed" ? "expanded" : "collapsed";
+          applyShellState(shell);
+        }
+      });
+    }
